import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "Blog",
  subtitle: "Latest insights, security research, and updates from the CyberVault security team.",
  sections: [
    {
      title: "Recent Articles",
      gridClass: "blog-grid",
      grid: [
        {
          title: "The Future of AI in Cybersecurity",
          description: "Exploring how machine learning is transforming threat detection and response.",
          meta: "Security Research • 5 min read",
          cta: { text: "Read More →", link: "/blog/ai-cybersecurity-future" }
        },
        {
          title: "Zero-Trust Implementation Guide",
          description: "Step-by-step guide to implementing zero-trust architecture in your organization.",
          meta: "Implementation • 12 min read",
          cta: { text: "Read More →", link: "/blog/zero-trust-guide" }
        },
        {
          title: "Quantum-Resistant Cryptography",
          description: "Why your organization needs to prepare for quantum computing threats today.",
          meta: "Cryptography • 8 min read",
          cta: { text: "Read More →", link: "/blog/quantum-crypto-prep" }
        },
        {
          title: "2025 Threat Landscape Report",
          description: "Comprehensive analysis of the top cybersecurity threats facing enterprises.",
          meta: "Research Report • 15 min read",
          cta: { text: "Read More →", link: "/blog/threat-landscape-2025" }
        },
        {
          title: "Ransomware Defense Strategies",
          description: "Best practices for protecting against and responding to ransomware attacks.",
          meta: "Threat Analysis • 10 min read",
          cta: { text: "Read More →", link: "/blog/ransomware-defense" }
        },
        {
          title: "Cloud Security Best Practices",
          description: "Essential security measures for AWS, Azure, and GCP environments.",
          meta: "Cloud Security • 7 min read",
          cta: { text: "Read More →", link: "/blog/cloud-security-practices" }
        }
      ]
    },
    {
      title: "Categories",
      bgColor: "#f8fafc",
      gridClass: "info-grid-4",
      grid: [
        { title: "Threat Analysis", description: "Deep dives into emerging threats" },
        { title: "Product Updates", description: "New features and improvements" },
        { title: "Security Research", description: "Research papers and findings" },
        { title: "Best Practices", description: "Security implementation guides" }
      ]
    }
  ],
  color: "#ec4899"
};

function Blog() {
  return <InfoPageLayout {...pageData} />;
}

export default Blog;
